import React, { useEffect, useState, useMemo } from "react";
import { api } from "../utils/api";

const DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
const MONTHS = ["January","February","March","April","May","June","July","August","September","October","November","December"];

export default function Calendar() {
  const [sessions, setSessions]     = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [today]   = useState(new Date());
  const [current, setCurrent] = useState({ year: new Date().getFullYear(), month: new Date().getMonth() });

  useEffect(() => {
    api.getSessions().then(setSessions);
    api.getAssignments().then(setAssignments);
  }, []);

  // Build event map: { "YYYY-MM-DD": [{ type, label }] }
  const eventMap = useMemo(() => {
    const map = {};
    const add = (date, event) => {
      if (!date) return;
      const key = date.slice(0, 10);
      if (!map[key]) map[key] = [];
      map[key].push(event);
    };
    sessions.forEach(s => add(s.date, { type: "session", label: s.label || "Class Session" }));
    assignments.forEach(a => { if (a.dueDate) add(a.dueDate, { type: "assignment", label: a.title }); });
    return map;
  }, [sessions, assignments]);

  // Build calendar grid
  const days = useMemo(() => {
    const { year, month } = current;
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const daysInPrev  = new Date(year, month, 0).getDate();
    const cells = [];

    // Prev month padding
    for (let i = firstDay - 1; i >= 0; i--) {
      cells.push({ day: daysInPrev - i, current: false, date: null });
    }
    // Current month
    for (let d = 1; d <= daysInMonth; d++) {
      const date = `${year}-${String(month + 1).padStart(2,"0")}-${String(d).padStart(2,"0")}`;
      cells.push({ day: d, current: true, date });
    }
    // Next month padding
    const remaining = 42 - cells.length;
    for (let d = 1; d <= remaining; d++) {
      cells.push({ day: d, current: false, date: null });
    }
    return cells;
  }, [current]);

  const prev = () => setCurrent(c => c.month === 0 ? { year: c.year - 1, month: 11 } : { ...c, month: c.month - 1 });
  const next = () => setCurrent(c => c.month === 11 ? { year: c.year + 1, month: 0 } : { ...c, month: c.month + 1 });
  const isToday = (date) => date && date === `${today.getFullYear()}-${String(today.getMonth()+1).padStart(2,"0")}-${String(today.getDate()).padStart(2,"0")}`;

  // Upcoming events list
  const upcoming = useMemo(() => {
    const todayStr = `${today.getFullYear()}-${String(today.getMonth()+1).padStart(2,"0")}-${String(today.getDate()).padStart(2,"0")}`;
    const events = [];
    sessions.forEach(s => { if (s.date >= todayStr) events.push({ date: s.date, type: "session", label: s.label || "Class Session" }); });
    assignments.forEach(a => { if (a.dueDate && a.dueDate >= todayStr) events.push({ date: a.dueDate, type: "assignment", label: `Due: ${a.title}` }); });
    return events.sort((a, b) => a.date.localeCompare(b.date)).slice(0, 8);
  }, [sessions, assignments, today]);

  return (
    <div>
      <div className="page-header">
        <div><h2>Calendar</h2><p>All sessions and assignment due dates</p></div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 260px", gap: 20, alignItems: "start" }}>
        {/* Main calendar */}
        <div className="card">
          {/* Nav */}
          <div className="cal-nav">
            <h3>{MONTHS[current.month]} {current.year}</h3>
            <button className="cal-nav-btn" onClick={prev}>‹</button>
            <button className="cal-nav-btn" onClick={() => setCurrent({ year: today.getFullYear(), month: today.getMonth() })}>Today</button>
            <button className="cal-nav-btn" onClick={next}>›</button>
          </div>

          {/* Day headers */}
          <div className="calendar-grid" style={{ marginBottom: 4 }}>
            {DAYS.map(d => <div key={d} className="cal-header">{d}</div>)}
          </div>

          {/* Day cells */}
          <div className="calendar-grid">
            {days.map((cell, i) => (
              <div key={i} className={`cal-day ${!cell.current ? "other-month" : ""} ${isToday(cell.date) ? "today" : ""}`}>
                <div className="cal-day-num">{cell.day}</div>
                {cell.date && (eventMap[cell.date] || []).map((ev, j) => (
                  <div key={j} className={`cal-event ${ev.type}`}>{ev.label}</div>
                ))}
              </div>
            ))}
          </div>

          {/* Legend */}
          <div style={{ display: "flex", gap: 16, marginTop: 16, paddingTop: 14, borderTop: "1px solid var(--border)" }}>
            {[
              { cls: "session",    label: "Class Session" },
              { cls: "assignment", label: "Assignment Due" },
            ].map(l => (
              <div key={l.cls} style={{ display: "flex", alignItems: "center", gap: 6 }}>
                <div className={`cal-event ${l.cls}`} style={{ margin: 0, fontSize: "0.65rem" }}>●</div>
                <span style={{ fontSize: "0.75rem", color: "var(--text-muted)" }}>{l.label}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Upcoming sidebar */}
        <div className="card">
          <div className="section-header" style={{ marginBottom: 14 }}>
            <h3>Upcoming</h3>
          </div>
          {upcoming.length === 0 ? (
            <div style={{ color: "var(--text-muted)", fontSize: "0.85rem", textAlign: "center", padding: "24px 0" }}>
              Nothing coming up!
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {upcoming.map((ev, i) => (
                <div key={i} style={{
                  padding: "10px 12px", borderRadius: "var(--radius)",
                  background: "var(--surface-2)", border: "1px solid var(--border)",
                  borderLeft: `3px solid ${ev.type === "session" ? "var(--indigo)" : "var(--amber)"}`,
                }}>
                  <div style={{ fontSize: "0.78rem", fontWeight: 600, color: "var(--text)", marginBottom: 2 }}>
                    {ev.label}
                  </div>
                  <div style={{ fontSize: "0.7rem", color: "var(--text-light)" }}>
                    {new Date(ev.date + "T12:00:00").toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
                  </div>
                  <span className={`badge ${ev.type === "session" ? "badge-coral" : "badge-warn"}`} style={{ marginTop: 6, fontSize: "0.62rem" }}>
                    {ev.type === "session" ? "Session" : "Assignment"}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
